<?php
namespace App\Domain\Combat;
use App\Domain\Combat\Data\CombatAction;use App\Domain\Combat\Data\CombatantStats;use App\Domain\Combat\Data\CombatResult;use App\Domain\Combat\Data\CombatRound;use App\Domain\Random\RandomNumberGenerator;
final class CombatSimulator {const MAX_ROUNDS=100;private $rng;public function __construct(RandomNumberGenerator $rng){$this->rng=$rng;}public function simulate(CombatantStats $character,CombatantStats $monster){$ch=$character->currentHealth();$mh=$monster->currentHealth();$initial=$this->initial($character,$monster,$ch,$mh);if($initial)return$initial;$rounds=[];for($n=1;$n<=self::MAX_ROUNDS;$n++){$actions=[];$first=$character->attackSpeed()>=$monster->attackSpeed();if($first){$actions[]=$this->attack($n,$character,$monster,$mh);$mh=end($actions)->defenderHealthAfter();if($mh>0){$actions[]=$this->attack($n,$monster,$character,$ch);$ch=end($actions)->defenderHealthAfter();}}else{$actions[]=$this->attack($n,$monster,$character,$ch);$ch=end($actions)->defenderHealthAfter();if($ch>0){$actions[]=$this->attack($n,$character,$monster,$mh);$mh=end($actions)->defenderHealthAfter();}}$rounds[]=new CombatRound($n,$actions);if($ch<=0||$mh<=0)break;}if($mh<=0){$s=CombatResultStatus::CHARACTER_VICTORY;$w=$character->identifier();}elseif($ch<=0){$s=CombatResultStatus::MONSTER_VICTORY;$w=$monster->identifier();}else{$s=CombatResultStatus::DRAW;$w=null;}return new CombatResult($s,$w,count($rounds),$character->currentHealth(),$ch,$monster->currentHealth(),$mh,$rounds);}private function initial($c,$m,$ch,$mh){if($ch>0&&$mh>0)return null;if($ch===0&&$mh===0){$s=CombatResultStatus::DRAW;$w=null;}elseif($ch===0){$s=CombatResultStatus::MONSTER_VICTORY;$w=$m->identifier();}else{$s=CombatResultStatus::CHARACTER_VICTORY;$w=$c->identifier();}return new CombatResult($s,$w,0,$ch,$ch,$mh,$mh,[]);}private function attack($round,$a,$d,$health){$chance=max(5,min(95,75+$a->accuracyRate()-$d->evasionRate()));$roll=$this->rng->randomInt(1,10000);$hit=$roll<=(int)round($chance*100);$cc=max(0,min(100,$a->criticalChance()));$cr=null;$critical=false;$damage=0;if($hit){$cr=$this->rng->randomInt(1,10000);$critical=$cr<=(int)round($cc*100);$damage=max(1,(int)round($a->attack()*(1-$d->damageReductionRate()/100)*($critical?$a->criticalDamageMultiplier():1)));}$after=max(0,$health-$damage);return new CombatAction($round,$a->identifier(),$d->identifier(),round($chance,2),$roll/100,$hit,round($cc,2),$cr===null?null:$cr/100,$critical,$damage,$health,$after);}}
